code = """import json

# Get data from storage using correct key names
cases_file_path = locals()['var_functions.query_db:14']
order_items_list = locals()['var_functions.query_db:16']

# Read the full cases data from the file
with open(cases_file_path, 'r') as f:
    cases_data = json.load(f)

# Process order item IDs
order_item_ids = [item['Id'].replace('#', '').strip() for item in order_items_list]

print('Number of order item IDs to match:', len(order_item_ids))
print('Number of cases from last 5 months:', len(cases_data))

# Filter cases where orderitemid__c matches any of the order item IDs
matching_cases = []
for case in cases_data:
    case_orderitem = str(case.get('orderitemid__c', '') or '').replace('#', '').strip()
    if case_orderitem in order_item_ids:
        matching_cases.append(case)

print('Matching cases found:', len(matching_cases))

if matching_cases:
    # Count frequency of each issueid__c
    from collections import Counter
    issue_counter = Counter()
    for case in matching_cases:
        issue_id = case.get('issueid__c', '')
        if issue_id:
            issue_counter[issue_id] += 1
    
    print('Total distinct issues:', len(issue_counter))
    
    if issue_counter:
        most_common = issue_counter.most_common(5)
        print('Top 5 most common issues:', most_common)
        
        # Get the most frequent issue ID
        most_frequent_issue = most_common[0][0]
        print('Most frequent issue ID:', most_frequent_issue)
    else:
        print('No issues found')
else:
    print('No matching cases found')"""

